import{u as o,j as n}from"./index-CaddwIly.js";import{L as r}from"./LegalPageLayout-z9cBBUzl.js";function c(){const{lang:t}=o(),e=t==="it",i=e?[{label:"Stato del sito",value:"Demo scolastica non ufficiale pubblicata su Vercel."},{label:"Dati attivi",value:"Preferenze tecniche locali, richieste meteo verso Open-Meteo e dati tecnici di navigazione."},{label:"Moduli",value:"Il form email presente nella home è disattivato e non deve essere usato."}]:[{label:"Site status",value:"Unofficial school demo published on Vercel."},{label:"Active data",value:"Local technical preferences, weather requests to Open-Meteo, and technical browsing data."},{label:"Forms",value:"The email form shown on the home page is disabled and must not be used."}],a=e?[{title:"Natura del progetto",paragraphs:["Questo sito è pubblicato come progetto scolastico dimostrativo non ufficiale. Non è il sito ufficiale della Transiberiana d'Abruzzo, non eroga servizi commerciali e non gestisce prenotazioni o newsletter.","Prima di un eventuale utilizzo pubblico definitivo o commerciale, questa informativa dovrà essere aggiornata con i dati reali del titolare del trattamento e con un recapito dedicato."]},{title:"Quali dati possono essere trattati",list:["Dati tecnici di navigazione normalmente generati quando una pagina web viene caricata tramite hosting e infrastruttura di rete.","Preferenze locali salvate sul dispositivo dell'utente per ricordare lingua, tema grafico e chiusura dell'avviso informativo.","Richieste verso il servizio Open-Meteo necessarie alla sezione meteo live.","Dati trasmessi solo se l'utente apre volontariamente link esterni verso servizi di terze parti, come Google Maps, Trainline o TripAdvisor."],note:"Il modulo email presente nella home è disattivato: non raccoglie dati, non invia messaggi e non deve essere usato per conferire informazioni personali."},{title:"Finalità e basi del trattamento nello stato attuale",list:["Fornire la normale visualizzazione tecnica del sito demo.","Ricordare preferenze strettamente funzionali richieste dall'utente, come lingua e tema.","Mostrare dati meteo pubblici tramite integrazione con Open-Meteo.","Documentare in modo trasparente il funzionamento della demo e i suoi limiti."],paragraphs:["Nello stato attuale non viene svolta attività di marketing, profilazione, newsletter o vendita online."]},{title:"Destinatari e servizi di terze parti",paragraphs:["Per motivi tecnici, parte dei dati di navigazione può transitare tramite il provider di hosting della demo, attualmente indicato come Vercel, e tramite il servizio Open-Meteo per la sezione meteo.","I servizi esterni come Google Maps, Trainline e TripAdvisor non vengono caricati automaticamente nelle pagine tramite embed invasivi: vengono aperti solo su iniziativa dell'utente tramite link."]},{title:"Conservazione dei dati",list:["Le preferenze locali restano sul dispositivo dell'utente fino a nuova scelta dell'utente stesso o alla cancellazione dei dati del browser.","I log tecnici lato hosting seguono le politiche del provider usato per pubblicare la demo.","Non esiste un database attivo di email o contatti raccolti tramite il sito in questa fase dimostrativa."]},{title:"Diritti e contatti",paragraphs:["Poiché il sito è una demo scolastica non ufficiale e non è destinato alla raccolta attiva di dati personali, al momento non viene pubblicato un recapito dedicato per richieste privacy tramite il sito.","Prima di un uso reale o istituzionale dovranno essere pubblicati il titolare del trattamento, i contatti diretti e le modalità per esercitare i diritti previsti dal GDPR."],note:"Finché questa demo resta in questa forma, non inserire dati personali nei campi non attivi o in eventuali contenuti dimostrativi."}]:[{title:"Project scope",paragraphs:["This website is published as an unofficial school demo. It is not the official Transiberiana d'Abruzzo website, it does not provide commercial services, and it does not manage bookings or newsletters.","Before any real public or commercial use, this notice must be updated with the actual controller details and a dedicated contact channel."]},{title:"What data may be involved",list:["Technical browsing data normally generated when a web page is delivered through hosting and network infrastructure.","Local preferences stored on the device to remember language, theme, and dismissal of the informational notice.","Requests sent to Open-Meteo in order to display the live weather section.","Data transmitted only if the user intentionally opens external links to third-party services such as Google Maps, Trainline, or TripAdvisor."],note:"The email form shown on the home page is disabled: it does not collect data, it does not send messages, and it must not be used to submit personal information."},{title:"Current purposes and legal basis",list:["Deliver the normal technical rendering of the demo website.","Remember strictly functional preferences requested by the user, such as language and theme.","Display public weather data through the Open-Meteo integration.","Explain transparently how the demo works and what its limits are."],paragraphs:["At this stage the website does not run marketing, profiling, newsletters, or online sales."]},{title:"Recipients and third-party services",paragraphs:["For technical reasons, some browsing data may transit through the hosting provider used for the demo, currently indicated as Vercel, and through Open-Meteo for the weather section.","External services such as Google Maps, Trainline, and TripAdvisor are not automatically embedded with invasive loading behavior: they are opened only when the user chooses to follow an external link."]},{title:"Retention",list:["Local preferences remain on the user device until the user changes them or clears browser data.","Technical hosting logs follow the retention rules of the provider used to publish the demo.","There is no active email or contact database collected through the website at this stage."]},{title:"Rights and contacts",paragraphs:["Because the website is an unofficial school demo and is not intended to actively collect personal data, no dedicated privacy contact channel is currently published through the website itself.","Before any real or institutional use, the controller identity, direct contacts, and procedures for exercising GDPR rights must be published."],note:"While the demo remains in this form, do not submit personal data through disabled fields or demonstrative content."}];return n.jsx(r,{badge:"Privacy",title:"Privacy Policy",intro:e?"Questa pagina descrive il trattamento dei dati nello stato attuale della demo scolastica pubblicata online.":"This page describes data handling in the current state of the school demo published online.",meta:i,sections:a})}export{c as default};
